// api/partner-photo.js
//
// Pipeline :
//   1. Watermarkly  → détecte plaque + place logo AutoEasy
//   2. Photoroom v2 → détourage PNG transparent (voiture + ombre)
//   3. Sharp        → fond gris + filigrane tuilé + voiture par-dessus
//   4. Sharp        → vignette AE en haut à droite
//
// Variables Vercel : PHOTOROOM_API_KEY  WATERMARKLY_API_KEY  AUTOEASY_LOGO_URL  VIGNETTE_URL

const FormData = require("form-data");
const fetch    = require("node-fetch");
const sharp    = require("sharp");

const BACKGROUND_COLOR = { r: 242, g: 242, b: 242 }; // #F2F2F2
const BG_HEX           = "#F2F2F2";

// Filigrane CoteCars — PNG transparent embarqué
const WATERMARK_B64 = "";

// ─────────────────────────────────────────────────────────────────────────────
// RETRY HELPER
// ─────────────────────────────────────────────────────────────────────────────
async function withRetry(fn, maxAttempts = 3, backoffMs = [0, 2000, 4000]) {
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    if (backoffMs[attempt] > 0) {
      await new Promise(r => setTimeout(r, backoffMs[attempt]));
    }
    try {
      return await fn();
    } catch (err) {
      const msg         = err.message || "";
      const isRetryable = msg.includes("503") || msg.includes("429") ||
                          msg.includes("Service Unavailable") ||
                          msg.includes("Too Many Requests");
      console.warn(`[retry] Tentative ${attempt + 1}/${maxAttempts} — ${msg}`);
      if (!isRetryable || attempt === maxAttempts - 1) throw err;
    }
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// ÉTAPE 1 — WATERMARKLY
// ─────────────────────────────────────────────────────────────────────────────
async function blurPlateWatermarkly(imageBuffer) {
  try {
    const API_URL = "https://blur-api-eu1.watermarkly.com/blur/";
    const API_KEY = process.env.WATERMARKLY_API_KEY;
    const logoUrl = process.env.AUTOEASY_LOGO_URL || "";

    const params = new URLSearchParams({
      blur_intensity:      "10",
      format:              "jpeg",
      detection_threshold: "0.3",
    });

    if (logoUrl) {
      params.set("logo_url",  logoUrl);
      params.set("logo_size", "1.0");
    }

    const res = await withRetry(() =>
      fetch(`${API_URL}?${params.toString()}`, {
        method:  "POST",
        headers: { "x-api-key": API_KEY, "Content-Type": "application/octet-stream" },
        body:    imageBuffer,
      })
    );

    if (!res.ok) {
      console.warn(`[Watermarkly] Erreur ${res.status}`);
      return null;
    }

    const buf = Buffer.from(await res.arrayBuffer());
    console.log(`[Watermarkly] OK — ${buf.length} octets`);
    return buf;

  } catch (err) {
    console.warn("[Watermarkly] Erreur :", err.message);
    return null;
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// ÉTAPE 2 — PHOTOROOM v2 → PNG transparent
// ─────────────────────────────────────────────────────────────────────────────
async function runPhotoroom(imageBuffer, mimeType) {
  const form = new FormData();
  form.append("imageFile",  imageBuffer, { filename: "car.jpg", contentType: mimeType });
  form.append("format",     "png");           // ← PNG transparent
  form.append("outputSize", "originalImage");
  form.append("padding",    "0.05");
  form.append("shadow.mode", "ai.soft");
  // Pas de background.color → fond transparent

  const res = await withRetry(() =>
    fetch("https://image-api.photoroom.com/v2/edit", {
      method:  "POST",
      headers: { "x-api-key": process.env.PHOTOROOM_API_KEY, ...form.getHeaders() },
      body:    form,
    })
  );

  if (!res.ok) {
    const errText = await res.text().catch(() => "");
    throw new Error(`Photoroom erreur ${res.status} : ${errText}`);
  }

  return Buffer.from(await res.arrayBuffer());
}

// ─────────────────────────────────────────────────────────────────────────────
// ÉTAPE 3 — Fond gris + filigrane tuilé + voiture par-dessus
//
// 1. Fond gris #F2F2F2 plein format
// 2. Filigrane tuilé à 10% d'opacité sur le fond
// 3. PNG transparent Photoroom (voiture + ombre) composité par-dessus
//    → voiture masque le filigrane
//    → ombre semi-transparente se fond naturellement
// ─────────────────────────────────────────────────────────────────────────────
async function compositeWithWatermark(carPngBuffer, width, height) {
  const wmBuffer = Buffer.from(WATERMARK_B64, "base64");

  // Taille d'une tuile : 1/4 de la largeur
  const tileW  = Math.round(width / 4);
  const wmMeta = await sharp(wmBuffer).metadata();
  const tileH  = Math.round(tileW * wmMeta.height / wmMeta.width);

  // Redimensionner + réduire opacité à 10%
  const { data: rawTile, info: tileInfo } = await sharp(wmBuffer)
    .resize(tileW, tileH)
    .ensureAlpha()
    .raw()
    .toBuffer({ resolveWithObject: true });

  const OPACITY = 0.25; // 25%
  for (let i = 3; i < rawTile.length; i += 4) {
    rawTile[i] = Math.round(rawTile[i] * OPACITY);
  }

  const tile = await sharp(rawTile, {
    raw: { width: tileInfo.width, height: tileInfo.height, channels: 4 }
  }).png().toBuffer();

  // Construire les positions de tuiles
  const composites = [];
  for (let y = 0; y < height; y += tileH) {
    for (let x = 0; x < width; x += tileW) {
      composites.push({ input: tile, top: y, left: x });
    }
  }

  // Ajouter la voiture PNG par-dessus (en dernier)
  composites.push({ input: carPngBuffer, top: 0, left: 0 });

  // Créer fond gris + tout assembler
  const result = await sharp({
    create: { width, height, channels: 3, background: BACKGROUND_COLOR }
  })
    .composite(composites)
    .jpeg({ quality: 92 })
    .toBuffer();

  console.log(`[Watermark] Fond + ${composites.length - 1} tuiles + voiture — OK`);
  return result;
}

// ─────────────────────────────────────────────────────────────────────────────
// HANDLER PRINCIPAL
// ─────────────────────────────────────────────────────────────────────────────
module.exports = async function handler(req, res) {
  if (req.method !== "POST") {
    return res.status(405).json({ success: false, error: "Method not allowed" });
  }

  try {
    const { image } = req.body;
    if (!image) {
      return res.status(200).json({ success: false, error: 'Champ "image" manquant.' });
    }

    const base64Data  = image.includes(",") ? image.split(",")[1] : image;
    const mimeType    = image.includes("data:") ? image.split(";")[0].split(":")[1] : "image/jpeg";
    const imageBuffer = Buffer.from(base64Data, "base64");

    if (imageBuffer.length > 20 * 1024 * 1024) {
      return res.status(200).json({ success: false, error: "Image trop volumineuse (max 20 Mo)." });
    }

    // ── 1. Watermarkly ───────────────────────────────────────────────────────
    console.log("[Pipeline] Étape 1 — Watermarkly...");
    const watermarklyResult = await blurPlateWatermarkly(imageBuffer);
    if (!watermarklyResult) {
      console.warn("[Pipeline] Watermarkly échoué — image originale utilisée");
    }

    const imageForPhotoroom = watermarklyResult ?? imageBuffer;

    // ── 2. Photoroom PNG transparent ─────────────────────────────────────────
    console.log("[Pipeline] Étape 2 — Photoroom (PNG transparent)...");
    let carPngBuffer;
    try {
      carPngBuffer = await runPhotoroom(imageForPhotoroom, "image/jpeg");
    } catch (err) {
      return res.status(200).json({ success: false, error: err.message });
    }

    const { width: imgW, height: imgH } = await sharp(carPngBuffer).metadata();
    console.log(`[Pipeline] Photoroom OK — ${imgW}x${imgH}px`);

    // ── 3. Fond + filigrane + voiture ─────────────────────────────────────────
    console.log("[Pipeline] Étape 3 — Composition fond + filigrane + voiture...");
    let finalBuffer = await compositeWithWatermark(carPngBuffer, imgW, imgH);

    // ── 4. Vignette AE ───────────────────────────────────────────────────────
    const vignetteUrl = process.env.VIGNETTE_URL || "https://cotecars-test.vercel.app/vignette-AE.png";
    try {
      const vigRes     = await fetch(vignetteUrl);
      const vigBuf     = Buffer.from(await vigRes.arrayBuffer());
      const VIG_SIZE   = Math.round(imgW * 0.08);
      const VIG_PAD    = Math.round(imgW * 0.02);
      const vigResized = await sharp(vigBuf)
        .resize(VIG_SIZE, VIG_SIZE, { fit: "contain", background: { r: 0, g: 0, b: 0, alpha: 0 } })
        .toBuffer();
      finalBuffer = await sharp(finalBuffer)
        .composite([{ input: vigResized, top: VIG_PAD, left: imgW - VIG_SIZE - VIG_PAD }])
        .jpeg({ quality: 92 })
        .toBuffer();
      console.log(`[Pipeline] Vignette OK — ${VIG_SIZE}px`);
    } catch (e) {
      console.warn("[Pipeline] Vignette échouée :", e.message);
    }

    console.log(`[Pipeline] Terminé — ${finalBuffer.length} octets | plaque: ${!!watermarklyResult}`);

    return res.status(200).json({
      success:       true,
      result:        "data:image/jpeg;base64," + finalBuffer.toString("base64"),
      plateDetected: !!watermarklyResult,
    });

  } catch (error) {
    console.error("[partner-photo] Erreur inattendue :", error);
    return res.status(200).json({ success: false, error: error.message || "Erreur serveur inconnue." });
  }
};